import React, { useState, useEffect } from 'react';
import { ExerciseContent, ExerciseType } from '../types';
import { generateExercise, gradeShortAnswers } from '../services/geminiService';
import { PRESET_WORKSHEETS } from '../data/worksheets';
import { Button } from './Button';
import { BookOpen, CheckCircle, XCircle, RefreshCw, PenTool, FileText, Sparkles, MessageSquare } from 'lucide-react';
import { ArrowRight } from 'lucide-react';

interface ExerciseZoneProps {
  type: ExerciseType;
}

export const ExerciseZone: React.FC<ExerciseZoneProps> = ({ type }) => {
  const [mode, setMode] = useState<'ai' | 'worksheet'>(type === ExerciseType.GRAMMAR ? 'worksheet' : 'ai');
  const [content, setContent] = useState<ExerciseContent | null>(null);
  const [loading, setLoading] = useState(false);
  const [difficulty, setDifficulty] = useState('Intermediate');
  const [answers, setAnswers] = useState<Record<number, string>>({});
  const [submitted, setSubmitted] = useState(false);
  const [score, setScore] = useState(0);

  // Stores AI grading for short answers
  const [shortAnswerResults, setShortAnswerResults] = useState<Record<number, {correct: boolean, feedback: string}>>({});
  const [isGrading, setIsGrading] = useState(false);

  const fetchExercise = async () => {
    setLoading(true);
    setSubmitted(false);
    setAnswers({});
    setScore(0);
    setShortAnswerResults({});

    try {
      if (mode === 'worksheet' && type === ExerciseType.GRAMMAR) {
          // Load the preset worksheet (Using the first one for now, logic can be expanded)
          setContent(PRESET_WORKSHEETS[0]);
      } else {
          const data = await generateExercise(type, difficulty);
          setContent(data);
      }
    } catch (err) {
      console.error(err);
      alert("Failed to load exercise.");
    } finally {
      setLoading(false);
    }
  };

  // Initial load or when switching modes/types
  useEffect(() => {
    fetchExercise();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [type, mode]); 

  const handleAnswerSelect = (questionId: number, value: string) => {
    if (submitted) return;
    setAnswers(prev => ({ ...prev, [questionId]: value }));
  };

  const handleSubmit = async () => {
    if (!content) return;
    setIsGrading(true);

    try {
        let correctCount = 0;

        // 1. Check Multiple Choice Locally
        content.questions.forEach(q => {
          if (q.type !== 'short-answer' && answers[q.id] === q.correctAnswer) {
            correctCount++;
          }
        });

        // 2. Grade Short Answers via AI
        const shortAnswerQuestions = content.questions.filter(q => q.type === 'short-answer');
        if (shortAnswerQuestions.length > 0) {
            const results = await gradeShortAnswers(content.questions, answers);
            setShortAnswerResults(results);

            // Add short answer scores
            Object.values(results).forEach(r => {
                if (r.correct) correctCount++;
            });
        }

        setScore(correctCount);
        setSubmitted(true);
    } catch (e) {
        console.error("Grading failed", e);
        alert("There was an issue grading the text answers. Please try again.");
    } finally {
        setIsGrading(false);
    }
  };

  const getDifficultyColor = (diff: string) => {
    switch (diff) {
      case 'Beginner': return 'bg-green-100 text-green-800 border-green-200';
      case 'Intermediate': return 'bg-yellow-100 text-yellow-800 border-yellow-200';
      case 'Advanced': return 'bg-red-100 text-red-800 border-red-200';
      default: return 'bg-slate-100 text-slate-800';
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
        <div>
          <h2 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
            {type === ExerciseType.READING ? <BookOpen className="h-6 w-6 text-teal-500" /> : <PenTool className="h-6 w-6 text-indigo-500" />}
            {type === ExerciseType.READING ? 'Reading Comprehension' : 'Grammar Practice'}
          </h2>
          <div className="flex gap-4 mt-2">
             {type === ExerciseType.GRAMMAR && (
                 <div className="flex bg-slate-100 p-1 rounded-lg">
                     <button 
                        onClick={() => setMode('worksheet')}
                        className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${mode === 'worksheet' ? 'bg-white shadow text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                     >
                         <FileText className="h-3 w-3 inline mr-1" /> Worksheet
                     </button>
                     <button 
                        onClick={() => setMode('ai')}
                        className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${mode === 'ai' ? 'bg-white shadow text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                     >
                         <Sparkles className="h-3 w-3 inline mr-1" /> AI Generate
                     </button>
                 </div>
             )}
          </div>
        </div>

        <div className="flex items-center gap-3">
          {mode === 'ai' && (
              <select 
                value={difficulty}
                onChange={(e) => setDifficulty(e.target.value)}
                className={`px-4 py-2 rounded-lg border-2 font-medium text-sm focus:outline-none transition-colors ${getDifficultyColor(difficulty)}`}
                disabled={loading}
              >
                <option value="Beginner">Beginner</option>
                <option value="Intermediate">Intermediate</option>
                <option value="Advanced">Advanced</option>
              </select>
          )}
          <Button onClick={fetchExercise} isLoading={loading} variant="secondary">
            <RefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
            {mode === 'ai' ? 'New Exercise' : 'Reset Worksheet'}
          </Button>
        </div>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center h-64 text-slate-400">
           <div className="w-16 h-16 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
           <p>Loading content...</p>
        </div>
      ) : content ? (
        <div className="space-y-6 animate-fade-in">
          {/* Content Card */}
          {content.content && (
            <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200 prose prose-slate max-w-none">
                <h3 className="text-xl font-bold text-slate-800 mb-4">{content.title}</h3>
                <div className="text-lg leading-relaxed text-slate-700 whitespace-pre-wrap">
                {content.content}
                </div>
            </div>
          )}

          {/* Questions */}
          <div className="grid gap-6">
            {content.questions.map((q, idx) => {
              // Determine status for styling
              let isCorrect = false;
              let isWrong = false;
              let feedback = "";

              if (submitted) {
                  if (q.type === 'short-answer') {
                      const result = shortAnswerResults[q.id];
                      isCorrect = result?.correct || false;
                      isWrong = !isCorrect;
                      feedback = result?.feedback || "Grading pending...";
                  } else {
                      isCorrect = answers[q.id] === q.correctAnswer;
                      isWrong = !isCorrect;
                  }
              }

              const borderClass = submitted 
                ? (isCorrect ? 'border-green-200 bg-green-50/30' : 'border-red-200 bg-red-50/30') 
                : 'border-transparent';

              return (
                <div key={q.id} className={`bg-white p-6 rounded-2xl shadow-sm border-2 transition-colors ${borderClass}`}>
                  <h4 className="font-semibold text-slate-900 mb-4 flex items-start gap-3">
                    <span className="bg-slate-100 text-slate-600 px-2 py-0.5 rounded text-sm font-bold mt-0.5">{idx + 1}</span>
                    {q.text}
                  </h4>

                  <div className="pl-9">
                    {q.type === 'short-answer' ? (
                        <div className="space-y-3">
                            <textarea
                                value={answers[q.id] || ''}
                                onChange={(e) => handleAnswerSelect(q.id, e.target.value)}
                                disabled={submitted}
                                placeholder="Type your answer here..."
                                className="w-full p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-y min-h-[100px] bg-slate-50"
                            />
                            {submitted && (
                                <div className={`p-4 rounded-xl text-sm ${isCorrect ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                                    <div className="font-bold mb-1 flex items-center gap-2">
                                        <MessageSquare className="h-4 w-4" /> 
                                        {isCorrect ? 'Excellent!' : 'Needs Improvement'}
                                    </div>
                                    {feedback}
                                </div>
                            )}
                        </div>
                    ) : (
                        <div className="space-y-3">
                            {/* FIX: Ensure options exist before mapping */}
                            {q.options?.map((opt) => {
                            const isSelected = answers[q.id] === opt;
                            let btnClass = "w-full text-left px-4 py-3 rounded-xl border transition-all duration-200 flex items-center justify-between group ";

                            if (submitted) {
                                if (opt === q.correctAnswer) {
                                btnClass += "bg-green-100 border-green-400 text-green-800 font-medium";
                                } else if (isSelected) {
                                btnClass += "bg-red-100 border-red-400 text-red-800";
                                } else {
                                btnClass += "bg-slate-50 border-slate-200 text-slate-400 opacity-70";
                                }
                            } else {
                                if (isSelected) {
                                btnClass += "bg-indigo-50 border-indigo-500 text-indigo-700 font-medium shadow-sm";
                                } else {
                                btnClass += "bg-white border-slate-200 hover:border-indigo-300 hover:bg-slate-50 text-slate-700";
                                }
                            }

                            return (
                                <button
                                key={opt}
                                onClick={() => handleAnswerSelect(q.id, opt)}
                                disabled={submitted}
                                className={btnClass}
                                >
                                <span>{opt}</span>
                                {submitted && opt === q.correctAnswer && <CheckCircle className="h-5 w-5 text-green-600" />}
                                {submitted && isSelected && opt !== q.correctAnswer && <XCircle className="h-5 w-5 text-red-600" />}
                                </button>
                            );
                            })}
                        </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>

          {/* Action Bar */}
          <div className="sticky bottom-6 bg-white/90 backdrop-blur border border-slate-200 p-4 rounded-xl shadow-lg flex items-center justify-between z-10">
            <div className="text-sm font-medium text-slate-600">
              {submitted ? (
                <span className={score === content.questions.length ? "text-green-600" : "text-indigo-600"}>
                  Score: {score}/{content.questions.length}
                </span>
              ) : (
                <span>{Object.keys(answers).length}/{content.questions.length} Answered</span>
              )}
            </div>
            {!submitted && (
              <Button 
                onClick={handleSubmit} 
                disabled={isGrading || Object.keys(answers).length !== content.questions.length}
                isLoading={isGrading}
                className="w-48"
              >
                {isGrading ? 'Grading...' : 'Check Answers'}
              </Button>
            )}
            {submitted && (
               <Button onClick={fetchExercise} variant="secondary">
                 Next Exercise <ArrowRight className="h-4 w-4 ml-1" />
               </Button>
            )}
          </div>
        </div>
      ) : (
        <div className="text-center py-20 text-slate-400">Press 'New Exercise' to start.</div>
      )}
    </div>
  );
};

