const createWorksheet = (num: number): ExerciseContent => ({
  title: `Grade 8 English Worksheet ${num}`,
  content: "Complete the following multiple choice and short answer questions.",
  // We generate unique IDs for questions per worksheet to prevent key collisions if we ever render multiple
  questions: BASE_QUESTIONS.map((q, i) => ({...q, id: num * 100 + i + 1}))
});

// The specific worksheets requested (1-5, 7-10)
export const PRESET_WORKSHEETS: ExerciseContent[] = [
  1, 2, 3, 4, 5, 7, 8, 9, 10
].map(createWorksheet);

