import { PRESET_WORKSHEETS } from '../data/worksheets';
import { Button } from './Button';
import { BookOpen, CheckCircle, XCircle, RefreshCw, PenTool, FileText, Sparkles, MessageSquare, ExternalLink } from 'lucide-react';
import { ArrowRight } from 'lucide-react';

interface ExerciseZoneProps {
  type: ExerciseType;
}

export const ExerciseZone: React.FC<ExerciseZoneProps> = ({ type }) => {
  const [mode, setMode] = useState<'ai' | 'worksheet'>(type === ExerciseType.GRAMMAR ? 'worksheet' : 'ai');
  const [content, setContent] = useState<ExerciseContent | null>(null);
  const [loading, setLoading] = useState(false);
  const [difficulty, setDifficulty] = useState('Intermediate');
  const [answers, setAnswers] = useState<Record<number, string>>({});
  const [submitted, setSubmitted] = useState(false);
  const [score, setScore] = useState(0);

  // Stores AI grading for short answers
  const [shortAnswerResults, setShortAnswerResults] = useState<Record<number, {correct: boolean, feedback: string}>>({});
  const [isGrading, setIsGrading] = useState(false);

  const fetchExercise = async () => {
    setLoading(true);
    setSubmitted(false);
    setAnswers({});
    setScore(0);
    setShortAnswerResults({});

    try {
        if (mode === 'ai') {
          const data = await generateExercise(type, difficulty);
          setContent(data);
        } else {
            // Worksheet list is static, no fetch needed
            setContent(null);
        }
    } catch (err) {
      console.error(err);
      alert("Failed to load exercise.");
    } finally {
      setLoading(false);
    }
  };

  // Initial load
  useEffect(() => {
    if (mode === 'ai') fetchExercise();
    else setContent(null);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [type, mode]); 

  const handleAnswerSelect = (questionId: number, value: string) => {
    if (submitted) return;
    setAnswers(prev => ({ ...prev, [questionId]: value }));
  };

  const handleSubmit = async () => {
    if (!content) return;
    setIsGrading(true);

    try {
        let correctCount = 0;

        // 1. Check Multiple Choice Locally
        content.questions.forEach(q => {
          if (q.type !== 'short-answer' && answers[q.id] === q.correctAnswer) {
            correctCount++;
          }
        });

        // 2. Grade Short Answers via AI
        const shortAnswerQuestions = content.questions.filter(q => q.type === 'short-answer');
        if (shortAnswerQuestions.length > 0) {
            const results = await gradeShortAnswers(content.questions, answers);
            setShortAnswerResults(results);

            // Add short answer scores
            Object.values(results).forEach(r => {
                if (r.correct) correctCount++;
            });
        }

        setScore(correctCount);
        setSubmitted(true);
    } catch (e) {
        console.error("Grading failed", e);
        alert("There was an issue grading the text answers. Please try again.");
    } finally {
        setIsGrading(false);
    }
  };

  const openWorksheet = (num: number) => {
      window.open(`?worksheetId=${num}`, '_blank');
  };

  const getDifficultyColor = (diff: string) => {
    switch (diff) {
      case 'Beginner': return 'bg-green-100 text-green-800 border-green-200';
      case 'Intermediate': return 'bg-yellow-100 text-yellow-800 border-yellow-200';
      case 'Advanced': return 'bg-red-100 text-red-800 border-red-200';
      default: return 'bg-slate-100 text-slate-800';
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
        <div>
          <h2 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
            {type === ExerciseType.READING ? <BookOpen className="h-6 w-6 text-teal-500" /> : <PenTool className="h-6 w-6 text-indigo-500" />}
            {type === ExerciseType.READING ? 'Reading Comprehension' : 'Grammar Practice'}
          </h2>
          <div className="flex gap-4 mt-2">
             {type === ExerciseType.GRAMMAR && (
                 <div className="flex bg-slate-100 p-1 rounded-lg">
                     <button 
                        onClick={() => setMode('worksheet')}
                        className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${mode === 'worksheet' ? 'bg-white shadow text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                     >
                         <FileText className="h-3 w-3 inline mr-1" /> Worksheets
                     </button>
                     <button 
                        onClick={() => setMode('ai')}
                        className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${mode === 'ai' ? 'bg-white shadow text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                     >
                         <Sparkles className="h-3 w-3 inline mr-1" /> AI Generate
                     </button>
                 </div>
             )}
          </div>
        </div>

        <div className="flex items-center gap-3">
          {mode === 'ai' && (
              <select 
                value={difficulty}
                onChange={(e) => setDifficulty(e.target.value)}
                className={`px-4 py-2 rounded-lg border-2 font-medium text-sm focus:outline-none transition-colors ${getDifficultyColor(difficulty)}`}
                disabled={loading}
              >
                <option value="Beginner">Beginner</option>
                <option value="Intermediate">Intermediate</option>
                <option value="Advanced">Advanced</option>
              </select>
          )}
          {mode === 'ai' && (
            <Button onClick={fetchExercise} isLoading={loading} variant="secondary">
                <RefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
                New Exercise
            </Button>
          )}
        </div>
      </div>

      {mode === 'worksheet' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-fade-in">
              {PRESET_WORKSHEETS.map((ws) => {
                  const num = parseInt(ws.title.split('Worksheet ')[1]);
                  return (
                    <div key={ws.title} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:shadow-md transition-all flex flex-col justify-between group">
                        <div>
                            <div className="w-12 h-12 bg-indigo-50 group-hover:bg-indigo-100 transition-colors rounded-xl flex items-center justify-center text-indigo-600 mb-4">
                                <FileText className="h-6 w-6" />
                            </div>
                            <h3 className="font-bold text-lg text-slate-900 mb-2">{ws.title}</h3>
                            <p className="text-sm text-slate-500 mb-6">{ws.content}</p>
                        </div>
                        <Button variant="outline" onClick={() => openWorksheet(num)} className="w-full justify-between group-hover:border-indigo-200 group-hover:text-indigo-600">
                            Open Sheet <ExternalLink className="h-4 w-4" />
                        </Button>
                    </div>
                  );
              })}
          </div>
      ) : (
          /* AI Mode Content */
          <>
            {loading ? (
                <div className="flex flex-col items-center justify-center h-64 text-slate-400">
                <div className="w-16 h-16 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
                <p>Generating personalized content...</p>
                </div>
            ) : content ? (
                <div className="space-y-6 animate-fade-in">
                {/* Content Card */}
                {content.content && (
                    <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200 prose prose-slate max-w-none">
                        <h3 className="text-xl font-bold text-slate-800 mb-4">{content.title}</h3>
                        <div className="text-lg leading-relaxed text-slate-700 whitespace-pre-wrap">
                        {content.content}
                        </div>
                    </div>
                )}

                {/* Questions */}
                <div className="grid gap-6">
                    {content.questions.map((q, idx) => {
                    // Determine status for styling
                    let isCorrect = false;
                    let isWrong = false;
                    let feedback = "";

                    if (submitted) {
                        if (q.type === 'short-answer') {
                            const result = shortAnswerResults[q.id];
                            isCorrect = result?.correct || false;
                            isWrong = !isCorrect;
                            feedback = result?.feedback || "Grading pending...";
                        } else {
                            isCorrect = answers[q.id] === q.correctAnswer;
                            isWrong = !isCorrect;
                        }
                    }

                    const borderClass = submitted 
                        ? (isCorrect ? 'border-green-200 bg-green-50/30' : 'border-red-200 bg-red-50/30') 
                        : 'border-transparent';

                    return (
                        <div key={q.id} className={`bg-white p-6 rounded-2xl shadow-sm border-2 transition-colors ${borderClass}`}>
                        <h4 className="font-semibold text-slate-900 mb-4 flex items-start gap-3">
                            <span className="bg-slate-100 text-slate-600 px-2 py-0.5 rounded text-sm font-bold mt-0.5">{idx + 1}</span>
                            {q.text}
                        </h4>

                        <div className="pl-9">
                            {q.type === 'short-answer' ? (
                                <div className="space-y-3">
                                    <textarea
                                        value={answers[q.id] || ''}
                                        onChange={(e) => handleAnswerSelect(q.id, e.target.value)}
                                        disabled={submitted}
                                        placeholder="Type your answer here..."
                                        className="w-full p-4 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-y min-h-[100px] bg-slate-50"
                                    />
                                    {submitted && (
                                        <div className={`p-4 rounded-xl text-sm ${isCorrect ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                                            <div className="font-bold mb-1 flex items-center gap-2">
                                                <MessageSquare className="h-4 w-4" /> 
                                                {isCorrect ? 'Excellent!' : 'Needs Improvement'}
                                            </div>
                                            {feedback}
                                        </div>
                                    )}
                                </div>
                            ) : (
                                <div className="space-y-3">
                                    {q.options?.map((opt) => {
                                    const isSelected = answers[q.id] === opt;
                                    let btnClass = "w-full text-left px-4 py-3 rounded-xl border transition-all duration-200 flex items-center justify-between group ";

                                    if (submitted) {
                                        if (opt === q.correctAnswer) {
                                        btnClass += "bg-green-100 border-green-400 text-green-800 font-medium";
                                        } else if (isSelected) {
                                        btnClass += "bg-red-100 border-red-400 text-red-800";
                                        } else {
                                        btnClass += "bg-slate-50 border-slate-200 text-slate-400 opacity-70";
                                        }
                                    } else {
                                        if (isSelected) {
                                        btnClass += "bg-indigo-50 border-indigo-500 text-indigo-700 font-medium shadow-sm";
                                        } else {
                                        btnClass += "bg-white border-slate-200 hover:border-indigo-300 hover:bg-slate-50 text-slate-700";
                                        }
                                    }

                                    return (
                                        <button
                                        key={opt}
                                        onClick={() => handleAnswerSelect(q.id, opt)}
                                        disabled={submitted}
                                        className={btnClass}
                                        >
                                        <span>{opt}</span>
                                        {submitted && opt === q.correctAnswer && <CheckCircle className="h-5 w-5 text-green-600" />}
                                        {submitted && isSelected && opt !== q.correctAnswer && <XCircle className="h-5 w-5 text-red-600" />}
                                        </button>
                                    );
                                    })}
                                </div>
                            )}
                        </div>
                        </div>
                    );
                    })}
                </div>

                {/* Action Bar */}
                <div className="sticky bottom-6 bg-white/90 backdrop-blur border border-slate-200 p-4 rounded-xl shadow-lg flex items-center justify-between z-10">
                    <div className="text-sm font-medium text-slate-600">
                    {submitted ? (
                        <span className={score === content.questions.length ? "text-green-600" : "text-indigo-600"}>
                        Score: {score}/{content.questions.length}
                        </span>
                    ) : (
                        <span>{Object.keys(answers).length}/{content.questions.length} Answered</span>
                    )}
                    </div>
                    {!submitted && (
                    <Button 
                        onClick={handleSubmit} 
                        disabled={isGrading || Object.keys(answers).length !== content.questions.length}
                        isLoading={isGrading}
                        className="w-48"
                    >
                        {isGrading ? 'Grading...' : 'Check Answers'}
                    </Button>
                    )}
                    {submitted && (
                    <Button onClick={fetchExercise} variant="secondary">
                        Next Exercise <ArrowRight className="h-4 w-4 ml-1" />
                    </Button>
                    )}
                </div>
                </div>
            ) : (
                <div className="text-center py-20 text-slate-400">Press 'New Exercise' to start.</div>
            )}
          </>
      )}
    </div>
  );
};

export interface User {
  email: string;
  firstName: string;
  lastName: string;
  phone?: string;
  password?: string; // In a real app, never store plain text
}

export enum ExerciseType {
  GRAMMAR = 'GRAMMAR',
  READING = 'READING',
  ORAL = 'ORAL',
  TUTOR = 'TUTOR'
}

export interface Question {
  id: number;
  text: string;
  type?: 'multiple-choice' | 'short-answer';
  options?: string[];
  correctAnswer?: string; // For MC, this is the exact string. For Short Answer, this can be empty/unused on client.
}

export interface ExerciseContent {
  title: string;
  content?: string; // The reading passage or grammar context
  questions: Question[];
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export interface OralGrade {
  score: number;
  fluency: string;
  grammar: string;
  vocabulary: string;
  improvements: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { ExerciseContent, ExerciseType, Question, OralGrade } from "../types";

// Helper to ensure API key exists
const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

export const generateExercise = async (type: ExerciseType, difficulty: string): Promise<ExerciseContent> => {
  const ai = getClient();
  const model = "gemini-3-pro-preview";

  let prompt = "";
  if (type === ExerciseType.GRAMMAR) {
    prompt = `Create a ${difficulty} level English grammar exercise. 
    Focus on common mistakes or specific grammar rules suitable for this level.
    Provide 3 multiple choice questions.`;
  } else if (type === ExerciseType.READING) {
    prompt = `Write a short, engaging passage (approx 150 words) for a ${difficulty} level English learner.
    Then provide 3 reading comprehension questions based on the text.`;
  }

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          content: { type: Type.STRING, description: "The reading passage or grammar explanation context." },
          questions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.INTEGER },
                text: { type: Type.STRING },
                type: { type: Type.STRING, enum: ['multiple-choice'] },
                options: { type: Type.ARRAY, items: { type: Type.STRING } },
                correctAnswer: { type: Type.STRING }
              }
            }
          }
        }
      }
    }
  });

  if (!response.text) {
    throw new Error("Failed to generate exercise content");
  }

  // Ensure generated questions default to multiple-choice
  const data = JSON.parse(response.text) as ExerciseContent;
  data.questions = data.questions.map(q => ({...q, type: 'multiple-choice'}));
  return data;
};

export const gradeShortAnswers = async (questions: Question[], answers: Record<number, string>): Promise<Record<number, {correct: boolean, feedback: string}>> => {
    const ai = getClient();
    const model = "gemini-3-pro-preview";

    // Filter only short answers that have been answered
    const shortAnswerQuestions = questions.filter(q => q.type === 'short-answer' && answers[q.id]);

    if (shortAnswerQuestions.length === 0) return {};

    const promptItems = shortAnswerQuestions.map(q => ({
        id: q.id,
        question: q.text,
        userAnswer: answers[q.id]
    }));

    const prompt = `You are an English teacher. Grade the following student answers.
    For each answer, determine if it is "correct" (boolean) and provide "feedback" (string).

    Items to grade:
    ${JSON.stringify(promptItems)}
    `;

    const response = await ai.models.generateContent({
        model,
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    results: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                id: { type: Type.INTEGER },
                                correct: { type: Type.BOOLEAN },
                                feedback: { type: Type.STRING }
                            }
                        }
                    }
                }
            }
        }
    });

    if (!response.text) return {};

    const result = JSON.parse(response.text);
    const gradingMap: Record<number, {correct: boolean, feedback: string}> = {};

    result.results.forEach((item: any) => {
        gradingMap[item.id] = {
            correct: item.correct,
            feedback: item.feedback
        };
    });

    return gradingMap;
};

export const gradeOralSession = async (transcript: {role: string, text: string}[]): Promise<OralGrade> => {
    const ai = getClient();
    const model = "gemini-3-pro-preview"; // Use a strong model for analysis

    const prompt = `You are an expert English Language Examiner (like for IELTS or TOEFL). 
    Analyze the following transcript of a student's conversation with an AI tutor.

    Transcript:
    ${JSON.stringify(transcript)}

    Grade the student's performance (Role: 'user').
    Provide a score out of 100.
    Provide constructive feedback on:
    1. Fluency & Coherence
    2. Grammar & Accuracy
    3. Lexical Resource (Vocabulary)

    Also list 3 specific, actionable improvements they can make.
    `;

    const response = await ai.models.generateContent({
        model,
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    score: { type: Type.INTEGER },
                    fluency: { type: Type.STRING },
                    grammar: { type: Type.STRING },
                    vocabulary: { type: Type.STRING },
                    improvements: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
            }
        }
    });

    if (!response.text) {
        throw new Error("Failed to generate oral grade");
    }

    return JSON.parse(response.text) as OralGrade;
};

export const getTutorClient = () => getClient();

import React, { useState, useRef, useEffect } from 'react';
import { getTutorClient, gradeOralSession } from '../services/geminiService';
import { createBlob, decodeAudioData } from '../services/audioUtils';
import { Button } from './Button';
import { OralGrade } from '../types';
import { Mic, MicOff, Activity, GraduationCap, CheckCircle, BarChart3, RefreshCcw } from 'lucide-react';
import { LiveServerMessage, Modality } from '@google/genai';

export const OralExercise: React.FC = () => {
  const [isConnected, setIsConnected] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Grading State
  const [isGrading, setIsGrading] = useState(false);
  const [gradingResult, setGradingResult] = useState<OralGrade | null>(null);

  // Refs for audio handling
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sessionRef = useRef<Promise<any> | null>(null);
  const closeSessionRef = useRef<(() => void) | null>(null);

  // Refs for transcription
  const transcriptRef = useRef<{role: string, text: string}[]>([]);
  const currentInputRef = useRef('');
  const currentOutputRef = useRef('');

  const startSession = async () => {
    setError(null);
    setGradingResult(null);
    transcriptRef.current = [];
    currentInputRef.current = '';
    currentOutputRef.current = '';

    try {
      const client = getTutorClient();

      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      inputContextRef.current = new AudioContextClass({ sampleRate: 16000 });
      audioContextRef.current = new AudioContextClass({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const sessionPromise = client.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          // Enable transcription to capture conversation for grading
          inputAudioTranscription: { model: "google-default" },
          outputAudioTranscription: { model: "google-default" },
          systemInstruction: "You are a friendly English conversation partner. Correct my pronunciation gently if needed, but focus on keeping the conversation flowing. Ask questions to help me practice.",
        },
        callbacks: {
            onopen: () => {
                console.log("Live session opened");
                setIsConnected(true);
                setupAudioInput(sessionPromise);
            },
            onmessage: async (msg: LiveServerMessage) => {
                // Handle Audio
                const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (audioData && audioContextRef.current) {
                    await playAudioChunk(audioData);
                }

                // Handle Transcription
                if (msg.serverContent?.outputTranscription?.text) {
                    currentOutputRef.current += msg.serverContent.outputTranscription.text;
                }
                if (msg.serverContent?.inputTranscription?.text) {
                    currentInputRef.current += msg.serverContent.inputTranscription.text;
                }

                if (msg.serverContent?.turnComplete) {
                    // Turn complete implies an exchange happened
                    if (currentInputRef.current.trim()) {
                        transcriptRef.current.push({role: 'user', text: currentInputRef.current});
                        currentInputRef.current = '';
                    }
                    if (currentOutputRef.current.trim()) {
                        transcriptRef.current.push({role: 'model', text: currentOutputRef.current});
                        currentOutputRef.current = '';
                    }
                }
            },
            onclose: () => {
                console.log("Live session closed");
                setIsConnected(false);
                cleanup();
            },
            onerror: (err) => {
                console.error("Live session error", err);
                setError("Connection lost. Please try again.");
                setIsConnected(false);
                cleanup();
            }
        }
      });

      sessionRef.current = sessionPromise;

      sessionPromise.then(session => {
          closeSessionRef.current = () => session.close();
      });

    } catch (err: any) {
      console.error(err);
      setError(err.message || "Failed to start audio session");
      cleanup();
    }
  };

  const setupAudioInput = (sessionPromise: Promise<any>) => {
    if (!inputContextRef.current || !streamRef.current) return;

    const ctx = inputContextRef.current;
    const source = ctx.createMediaStreamSource(streamRef.current);
    const processor = ctx.createScriptProcessor(4096, 1, 1);

    processor.onaudioprocess = (e) => {
      if (isMuted) return;

      const inputData = e.inputBuffer.getChannelData(0);
      const pcmBlob = createBlob(inputData);

      sessionPromise.then(session => {
          session.sendRealtimeInput({ media: pcmBlob });
      });
    };

    source.connect(processor);
    processor.connect(ctx.destination);

    sourceRef.current = source;
    processorRef.current = processor;
  };

  const playAudioChunk = async (base64Audio: string) => {
    if (!audioContextRef.current) return;

    const ctx = audioContextRef.current;
    const arrayBuffer = await decodeAudioData(
        new Uint8Array(atob(base64Audio).split('').map(c => c.charCodeAt(0))),
        ctx,
        24000,
        1
    );

    const source = ctx.createBufferSource();
    source.buffer = arrayBuffer;
    source.connect(ctx.destination);

    const currentTime = ctx.currentTime;
    if (nextStartTimeRef.current < currentTime) {
        nextStartTimeRef.current = currentTime;
    }

    source.start(nextStartTimeRef.current);
    nextStartTimeRef.current += arrayBuffer.duration;
  };

  const cleanup = () => {
    if (closeSessionRef.current) closeSessionRef.current();
    if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    if (processorRef.current) processorRef.current.disconnect();
    if (sourceRef.current) sourceRef.current.disconnect();
    if (inputContextRef.current) inputContextRef.current.close();
    if (audioContextRef.current) audioContextRef.current.close();

    closeSessionRef.current = null;
    streamRef.current = null;
    sessionRef.current = null;
    setIsConnected(false);
  };

  const toggleMute = () => {
      setIsMuted(!isMuted);
  };

  const handleEndAndGrade = async () => {
    cleanup();
    setIsConnected(false);

    // Check if we have enough data
    const transcript = transcriptRef.current;
    // Capture any pending partials
