        console.error(e);
        setError("Failed to generate grade. Please try again.");
    } finally {
        setIsGrading(false);
    }
  };

  const reset = () => {
      setGradingResult(null);
      setError(null);
      setIsGrading(false);
  };

  useEffect(() => {
    return () => {
      cleanup();
    };
  }, []);

