                  </div>
                  <div className="bg-slate-50 p-4 rounded-xl border border-slate-200">
                      <h3 className="font-semibold text-slate-700 mb-2 flex items-center gap-2">
                          <CheckCircle size={18} className="text-green-500"/> Grammar
